// // This module decrements the counter on each clock cycle when the enable signal is high and resets the counter to seven when the reset signal is high.
module up_counter(
    input               clk         ,
    input               reset       ,
    input               enable      ,
    output  reg [2:0]   count
);

    always @(posedge clk) begin
        if (reset) begin
            count <= 3'b000;
        end else if (enable) begin
            count <= count + 1;
        end
    end

endmodule
